import React, { useState, useEffect } from 'react';
import { cameraAPI } from '../utils/api';
import CameraView from '../components/CameraView';
import toast from 'react-hot-toast';
import './CameraPage.css';

const DEFAULT_FORM = { camera_id: '', name: '', location: '', stream_url: '' };

export default function CameraPage() {
  const [cameras, setCameras] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState(DEFAULT_FORM);
  const [saving, setSaving] = useState(false);

  useEffect(() => { loadCameras(); }, []);

  const loadCameras = async () => {
    const res = await cameraAPI.list();
    setCameras(res.data.results || res.data);
  };

  const handleSave = async () => {
    if (!form.camera_id || !form.name || !form.location) {
      return toast.error('Fill in Camera ID, Name, and Location');
    }
    setSaving(true);
    try {
      await cameraAPI.create(form);
      toast.success('Camera added!');
      setForm(DEFAULT_FORM);
      setShowForm(false);
      loadCameras();
    } catch (e) {
      const msg = e?.response?.data;
      if (msg) {
        const text = typeof msg === 'string' ? msg : JSON.stringify(msg);
        toast.error(text);
      } else {
        toast.error('Error adding camera');
      }
    } finally { setSaving(false); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this camera?')) return;
    await cameraAPI.delete(id);
    toast.success('Deleted');
    loadCameras();
  };

  const activeCams = cameras.filter(c => c.is_active);

  return (
    <div>
      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
        <div>
          <h1>📹 Live Cameras</h1>
          <p>{activeCams.length} active camera{activeCams.length !== 1 ? 's' : ''}</p>
        </div>
        <button className="btn btn-primary" onClick={() => setShowForm(!showForm)}>
          {showForm ? '✕ Cancel' : '+ Add Camera'}
        </button>
      </div>

      {showForm && (
        <div className="card" style={{ marginBottom: 20 }}>
          <div className="card-title">Add New Camera</div>
          <div className="cam-form-grid">
            {[
              { key: 'camera_id', label: 'Camera ID', ph: 'e.g. cam_01' },
              { key: 'name', label: 'Name', ph: 'e.g. Main Gate Camera' },
              { key: 'location', label: 'Location', ph: 'e.g. Factory Entrance' },
              { key: 'stream_url', label: 'RTSP URL', ph: 'rtsp://user:pass@192.168.1.10:554/stream' },
            ].map(f => (
              <div key={f.key}>
                <label>{f.label}</label>
                <input value={form[f.key]} placeholder={f.ph}
                  onChange={e => setForm({ ...form, [f.key]: e.target.value })} />
              </div>
            ))}
          </div>
          <div style={{ display: 'flex', gap: 10, marginTop: 16 }}>
            <button className="btn btn-primary" onClick={handleSave} disabled={saving}>
              {saving ? 'Saving...' : '💾 Save Camera'}
            </button>
          </div>
        </div>
      )}

      {/* Camera list management */}
      {cameras.length > 0 && (
        <div className="cam-list-table card" style={{ marginBottom: 24 }}>
          <div className="card-title">Camera Management</div>
          <table className="live-table">
            <thead>
              <tr>
                <th>Camera ID</th><th>Name</th><th>Location</th><th>Status</th><th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {cameras.map(cam => (
                <tr key={cam.id}>
                  <td><code style={{ color: '#60a5fa' }}>{cam.camera_id}</code></td>
                  <td>{cam.name}</td>
                  <td>{cam.location}</td>
                  <td><span className={`badge ${cam.is_active ? 'badge-green' : 'badge-red'}`}>{cam.is_active ? 'Active' : 'Inactive'}</span></td>
                  <td>
                    <button className="btn btn-danger" style={{ padding: '4px 10px', fontSize: 12 }}
                      onClick={() => handleDelete(cam.id)}>Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Live camera feeds */}
      {activeCams.length > 0 ? (
        <div className={activeCams.length === 1 ? '' : 'grid-2'}>
          {activeCams.map(cam => <CameraView key={cam.camera_id} camera={cam} />)}
        </div>
      ) : (
        <div className="card" style={{ textAlign: 'center', padding: 60, color: '#475569' }}>
          <div style={{ fontSize: 48, marginBottom: 12 }}>📹</div>
          <div style={{ fontSize: 16, marginBottom: 8 }}>No active cameras</div>
          <div style={{ fontSize: 13 }}>Add a camera above to start live recognition</div>
        </div>
      )}
    </div>
  );
}
